def range_summary(nums):
    if not nums:
        return ''
    runs = []
    i, last = 0, None
    for n in sorted(set(nums)):
        if n == last + 1:
            continue
        if last is not None:
            runs.append((last, n - 1))
        runs.append(n)
        last = n
    result = ', '.join(str(x) for x in runs)
    for start, end in reversed(runs[::2]):
        if start != end - 1:
            result = f'{result}, {start}-{end}'
    return result
